#include <stdio.h>
#include <stdlib.h>
#define MAXN 200
#define MAXM 200
#define MAXQ 100000
int max(int a, int b) { return a > b ? a : b; }
int min(int a, int b) { return a < b ? a : b; }
int abs(int a) { return a < 0 ? -a : a; }
int main() {
    int N, M, Q;
    scanf("%d %d", &N, &M);
    char board[MAXN][MAXM];
    for (int i = 0; i < N; i++) {
        scanf("%s", board[i]);
    }
    scanf("%d", &Q);
    int c[MAXQ];
    for (int i = 0; i < Q; i++) {
        scanf("%d", &c[i]);
    }
    for (int i = 0; i < Q; i++) {
        int max_size = 0;
        for (int j = 0; j < N; j++) {
            for (int k = 0; k < M; k++) {
                int size = 1;
                int inversions = 0;
                for (int x = j; x < N && x < j + size; x++) {
                    for (int y = k; y < M && y < k + size; y++) {
                        if ((x + y) % 2 == 0 && board[x][y] != '0') {
                            inversions++;
                        }
                        if ((x + y) % 2 == 1 && board[x][y] != '1') {
                            inversions++;
                        }
                    }
                }
                if (inversions <= c[i]) {
                    max_size = max(max_size, size);
                }
                size++;
            }
        }
        printf("%d\n", max_size);
    }
    return 0;
}

