import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        char[][] board = new char[N][M];
        for (int i = 0; i < N; i++) {
            String row = scanner.next();
            for (int j = 0; j < M; j++) {
                board[i][j] = row.charAt(j);
            }
        }
        int Q = scanner.nextInt();
        int[] c = new int[Q];
        for (int i = 0; i < Q; i++) {
            c[i] = scanner.nextInt();
        }
        for (int i = 0; i < Q; i++) {
            int max_size = 0;
            for (int j = 0; j < N; j++) {
                for (int k = 0; k < M; k++) {
                    int size = 1;
                    int inversions = 0;
                    for (int x = j; x < N && x < j + size; x++) {
                        for (int y = k; y < M && y < k + size; y++) {
                            if ((x + y) % 2 == 0 && board[x][y] != '0') {
                                inversions++;
                            }
                            if ((x + y) % 2 == 1 && board[x][y] != '1') {
                                inversions++;
                            }
                        }
                    }
                    if (inversions <= c[i]) {
                        max_size = Math.max(max_size, size);
                    }
                    size++;
                }
            }
            System.out.println(max_size);
        }
    }
}

